#!/usr/bin/env python3
"""Install services/daily/* into the current directory.

Run this from inside your git repo root (e.g. ~/workspace):

    python3 install_daily.py

Creates services/daily/ with all files. Safe to re-run (overwrites).
"""
import base64
import os
import sys
from pathlib import Path

FILES = {
  ".replit": "",
  "Dockerfile": "",
  "app.py": "",
  "cloudflare-worker.js": "",
  "data.json": "",
  "db.py": "",
  "mcp_client.py": "",
  "neon-schema.sql": "",
  "poster.py": "",
  "railway.json": "",
  "render.py": "",
  "requirements.txt": "ZmFzdGFwaT09MC4xMTUuNgp1dmljb3JuW3N0YW5kYXJkXT09MC4zMi4xCmh0dHB4PT0wLjI4LjEKcHN5Y29wZ1tiaW5hcnldPT0zLjIuMwpib3RvMz09MS4zNS43NgptYXRwbG90bGliPT0zLjEwLjgKcGlsbG93PT0xMS4wLjAKbnVtcHk9PTIuMi4xCnR3ZWVweT09NC4xNC4wCg==",
  "storage.py": "",
  "wrangler.toml": ""
}

def main() -> int:
    target = Path.cwd() / "services" / "daily"
    target.mkdir(parents=True, exist_ok=True)
    for rel, b64 in FILES.items():
        dest = target / rel
        dest.parent.mkdir(parents=True, exist_ok=True)
        dest.write_bytes(base64.b64decode(b64))
        print(f"wrote {dest.relative_to(Path.cwd())}")
    print(f"\n{len(FILES)} files installed into services/daily/")
    print("Next: git add services/daily/ && git status | head -30")
    return 0

if __name__ == "__main__":
    sys.exit(main())
